/// Helper to safely deinit transformed ASTs while preserving PROGRAM_AST
fn maybeDeinitAst(source_ast: *const Program) void {
    if (source_ast == &PROGRAM_AST) {
        // This is the const PROGRAM_AST - don't deinit
        return;
    }
    // Heap-allocated transformed AST - safe to deinit
    var mutable_ast = @constCast(source_ast);
    mutable_ast.deinit();
}


